"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[6279],{93642(i,e,o){o.r(e),o.d(e,{assets:()=>c,contentTitle:()=>s,default:()=>m,frontMatter:()=>r,metadata:()=>n,toc:()=>l});const n=JSON.parse('{"id":"learning/courses/quantum-computing-in-practice/introduction","title":"Introduzione","description":"Un corso IBM gratuito sul quantum computing su scala utility, con casi d\'uso realistici e best practice","source":"@site/i18n/it/docusaurus-plugin-content-docs/current/learning/courses/quantum-computing-in-practice/introduction.mdx","sourceDirName":"learning/courses/quantum-computing-in-practice","slug":"/learning/courses/quantum-computing-in-practice/introduction","permalink":"/learning/courses/quantum-computing-in-practice/introduction","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/quantum-computing-in-practice/introduction.mdx","tags":[],"version":"current","frontMatter":{"title":"Introduzione","sidebar_label":"Introduzione","description":"Un corso IBM gratuito sul quantum computing su scala utility, con casi d\'uso realistici e best practice","notebook_path":"learning/courses/quantum-computing-in-practice/introduction.ipynb"},"sidebar":"tutorialsSidebar","previous":{"title":"Panoramica","permalink":"/learning/courses/quantum-computing-in-practice/"},"next":{"title":"Esecuzione di circuiti quantistici","permalink":"/learning/courses/quantum-computing-in-practice/running-quantum-circuits"}}');var a=o(74848),t=o(28453);const r={title:"Introduzione",sidebar_label:"Introduzione",description:"Un corso IBM gratuito sul quantum computing su scala utility, con casi d'uso realistici e best practice",notebook_path:"learning/courses/quantum-computing-in-practice/introduction.ipynb"},s="Introduzione al corso {#course-introduction}",c={},l=[{value:"Informazioni su questo corso",id:"about-this-course",level:2},{value:"Quantum utility",id:"quantum-utility",level:3},{value:"Simulare la Natura",id:"simulating-nature",level:3},{value:"Focus sui processori quantistici di maggiori dimensioni",id:"a-focus-on-larger-quantum-processors",level:3},{value:"Pubblico di destinazione e obiettivi del corso",id:"audience-and-course-goals",level:3},{value:"La storia della computazione",id:"the-story-of-computation",level:2},{value:"Dispositivi di calcolo dall&#39;antichit\xe0",id:"computing-devices-since-ancient-times",level:3},{value:"Connessioni con il mondo fisico",id:"connections-to-the-physical-world",level:3},{value:"La legge di Moore",id:"moores-law",level:3},{value:"Quantum computing",id:"quantum-computing",level:2},{value:"La meccanica quantistica e la computazione",id:"quantum-mechanics-and-computation",level:3},{value:"Il quantum computing in teoria",id:"quantum-computing-in-theory",level:3},{value:"Il quantum computing in pratica",id:"quantum-computing-in-practice",level:3},{value:"Potenziali applicazioni",id:"potential-applications",level:3},{value:"Stato della tecnologia",id:"state-of-the-technology",level:3},{value:"Conclusione",id:"conclusion",level:2}];function u(i){const e={a:"a",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",p:"p",strong:"strong",ul:"ul",...(0,t.R)(),...i.components},{IBMVideo:o}=e;return o||function(i,e){throw new Error("Expected "+(e?"component":"object")+" `"+i+"` to be defined: you likely forgot to import, pass, or provide it.")}("IBMVideo",!0),(0,a.jsxs)(a.Fragment,{children:["\n",(0,a.jsx)(e.header,{children:(0,a.jsx)(e.h1,{id:"course-introduction",children:"Introduzione al corso"})}),"\n",(0,a.jsxs)(e.p,{children:["Prima di iniziare, ti chiediamo di completare questo breve ",(0,a.jsx)(e.a,{href:"https://your.feedback.ibm.com/jfe/form/SV_6PadhMQiGWsxXTM",children:"sondaggio pre-corso"}),", che ci aiuta a migliorare i nostri contenuti e l'esperienza utente."]}),"\n",(0,a.jsxs)(e.p,{children:["Clicca qui sotto per ascoltare l'introduzione al corso di Olivia Lanes, oppure apri il video in una finestra separata su ",(0,a.jsx)(e.a,{href:"https://youtube.com/watch?v=sVRpKhCfKRI",children:"YouTube."})]}),"\n",(0,a.jsx)(o,{id:"134063425",title:"In this video, Olivia Lanes gives an overview of practical quantum computing in the utility era. She covers intended audience and some background on subjects like Moore's law and theoretical foundations of quantum computing."}),"\n",(0,a.jsx)(e.h2,{id:"about-this-course",children:"Informazioni su questo corso"}),"\n",(0,a.jsxs)(e.p,{children:["Benvenuto in ",(0,a.jsx)(e.em,{children:"Quantum Computing in Practice"})," \u2014 un corso incentrato sui computer quantistici di oggi e su come sfruttarli al massimo delle loro potenzialit\xe0.\nIl corso tratta potenziali casi d'uso realistici per il quantum computing, nonch\xe9 le best practice per eseguire esperimenti su processori quantistici con 100 o pi\xf9 qubit."]}),"\n",(0,a.jsx)(e.h3,{id:"quantum-utility",children:"Quantum utility"}),"\n",(0,a.jsxs)(e.p,{children:["\xc8 un momento entusiasmante per il quantum computing.\nDopo molti anni di ricerca e sviluppo teorico e sperimentale, i computer quantistici si avvicinano a un punto in cui possono iniziare a competere con i computer classici e dimostrare la loro ",(0,a.jsx)(e.em,{children:"utilit\xe0"}),"."]}),"\n",(0,a.jsxs)(e.p,{children:["L'utilit\xe0 non \xe8 la stessa cosa del ",(0,a.jsx)(e.em,{children:"quantum advantage"}),", che indica la capacit\xe0 dei computer quantistici di ",(0,a.jsx)(e.em,{children:"superare"})," i computer classici in compiti significativi.\nI computer classici hanno una potenza e un'adattabilit\xe0 straordinarie, e la realt\xe0 \xe8 che i computer quantistici semplicemente non sono ancora in grado di batterli.\nAbbiamo assistito a decenni di progressi nel campo del calcolo classico \u2014 non solo nell'hardware, ma anche negli algoritmi per i computer classici \u2014 ed \xe8 evidente che la tecnologia del calcolo digitale elettronico ha radicalmente trasformato il nostro mondo."]}),"\n",(0,a.jsxs)(e.p,{children:["Il quantum computing, d'altro canto, si trova in una fase diversa del suo sviluppo.\nIl quantum computing pone richieste estreme al nostro controllo dei sistemi quantomeccanici e spinge i limiti della tecnologia attuale \u2014 non possiamo aspettarci realisticamente di padroneggiare questa nuova tecnologia e di battere il calcolo classico fin dall'inizio.\nMa stiamo vedendo segnali che suggeriscono come i computer quantistici stiano iniziando a diventare competitivi con i metodi di calcolo classici per determinati compiti, il che rappresenta un passo naturale nell'evoluzione tecnologica del quantum computing, noto come ",(0,a.jsx)(e.em,{children:"quantum utility"}),"."]}),"\n",(0,a.jsx)(e.p,{children:"Man mano che la tecnologia avanza e vengono sviluppati nuovi metodi per il quantum computing, possiamo ragionevolmente aspettarci che i suoi vantaggi diventino sempre pi\xf9 marcati \u2014 ma questo richieder\xe0 tempo.\nCon il progredire di questa evoluzione, \xe8 probabile che assisteremo a un'interazione alternata con il calcolo classico:\nverranno effettuate dimostrazioni di quantum computing, il calcolo classico risponder\xe0, il quantum computing torner\xe0 in campo e questo schema si ripeter\xe0.\nE un giorno, quando le prestazioni di un computer quantistico non potranno essere eguagliate classicamente, ipotizzeremo di aver assistito a un quantum advantage \u2014 ma anche allora non ne saremo del tutto certi!\nDimostrare l'impossibilit\xe0 dei risultati per i computer classici \xe8, per quanto ne sappiamo, un problema a sua volta impossibilmente difficile."}),"\n",(0,a.jsx)(e.h3,{id:"simulating-nature",children:"Simulare la Natura"}),"\n",(0,a.jsx)(e.p,{children:"I simulatori classici \u2014 ovvero programmi software eseguiti su computer classici che simulano sistemi fisici \u2014 possono fare previsioni sui sistemi quantomeccanici.\nMa i simulatori classici non sono quantistici e non possono emulare direttamente i sistemi quantistici.\nUsano invece calcoli matematici per approssimare il comportamento quantistico.\nAll'aumentare delle dimensioni dei sistemi simulati, il costo computazionale necessario per farlo cresce in modo drastico, ponendo limiti ai sistemi quantistici che possono essere simulati classicamente, al tempo richiesto dalle simulazioni e alla precisione dei risultati."}),"\n",(0,a.jsx)(e.p,{children:"I computer quantistici, al contrario, possono emulare i sistemi quantistici in modo pi\xf9 diretto \u2014 e di conseguenza il loro costo computazionale scala significativamente meglio all'aumentare delle dimensioni del sistema.\nQuesta era, di fatto, l'intuizione di Richard Feynman negli anni '80, che per primo motiv\xf2 un'indagine sul potenziale dei computer quantistici.\nNe parleremo pi\xf9 avanti!"}),"\n",(0,a.jsx)(e.p,{children:"I ricercatori di IBM\xae hanno pubblicato nel 2023 un articolo che ha dimostrato, per la prima volta, che un computer quantistico pu\xf2 competere con le tecniche classiche allo stato dell'arte per la simulazione di un determinato modello fisico.\nI suoi risultati possono ancora essere eguagliati da tecniche avanzate eseguite su computer classici \u2014 ma ha superato gli algoritmi a forza bruta,\ne offre anche un nuovo punto di riferimento rispetto a cui confrontare diversi metodi di simulazione (che non sono esatti e non concordano tutti nelle loro previsioni)."}),"\n",(0,a.jsx)(e.h3,{id:"a-focus-on-larger-quantum-processors",children:"Focus sui processori quantistici di maggiori dimensioni"}),"\n",(0,a.jsx)(e.p,{children:"I precedenti utenti dell'hardware quantistico IBM avranno notato che i processori pi\xf9 piccoli precedentemente messi a disposizione del pubblico sono stati portati offline, lasciando spazio a processori pi\xf9 grandi (con 100+ qubit).\nQuei processori pi\xf9 piccoli potevano essere facilmente simulati classicamente.\nPertanto, pur rappresentando tappe accessibili al pubblico in una tecnologia in evoluzione, non potevano in alcun modo dimostrare la quantum utility: qualsiasi cosa fosse possibile fare con loro poteva essere fatta altrettanto facilmente con una simulazione classica."}),"\n",(0,a.jsxs)(e.p,{children:["Intorno ai 100 qubit, tuttavia, questo non \xe8 pi\xf9 il caso: processori quantistici di queste dimensioni non possono pi\xf9 essere simulati classicamente.\nQuesto rappresenta una sorta di transizione di fase verso una nuova era della tecnologia di quantum computing, in cui esiste il ",(0,a.jsx)(e.em,{children:"potenziale"})," per superare il calcolo classico.\n\xc8 qui che IBM ha scelto di concentrarsi \u2014 per ricercare la potenza di calcolo quantistica e tendere verso un eventuale quantum advantage."]}),"\n",(0,a.jsx)(e.p,{children:"Incoraggiamo i nostri utenti a sfruttare al massimo questi nuovi dispositivi, a sperimentare con essi, a spingerne i limiti e a portare avanti le lezioni apprese alla prossima generazione di processori quantistici attualmente in sviluppo.\nLo scopo di questo corso \xe8 metterti in condizione di farlo!"}),"\n",(0,a.jsx)(e.h3,{id:"audience-and-course-goals",children:"Pubblico di destinazione e obiettivi del corso"}),"\n",(0,a.jsx)(e.p,{children:"Questo corso \xe8 per chiunque voglia sviluppare nuove applicazioni per i computer quantistici, scalare il proprio lavoro attuale nel quantum computing, o imparare a utilizzare i processori quantistici nel proprio flusso di lavoro.\nInclude non solo fisici e informatici, ma anche ingegneri, chimici, scienziati dei materiali e chiunque altro sia interessato a padroneggiare l'hardware di quantum computing."}),"\n",(0,a.jsx)(e.p,{children:"Il corso sar\xe0 pratico e incentrato sull'uso concreto dei computer quantistici.\nTra gli argomenti e le competenze che tratter\xe0 vi sono i seguenti:"}),"\n",(0,a.jsxs)(e.ul,{children:["\n",(0,a.jsx)(e.li,{children:"Eseguire job su scala utility su processori quantistici tramite Qiskit Runtime"}),"\n",(0,a.jsx)(e.li,{children:"Usare tecniche di error mitigation per migliorare i risultati dell'hardware"}),"\n",(0,a.jsx)(e.li,{children:"Potenziali aree applicative per i computer quantistici a breve termine"}),"\n"]}),"\n",(0,a.jsxs)(e.p,{children:["Questo corso non tratta la teoria introduttiva del quantum computing e presuppone una conoscenza di base dei qubit e dei circuiti quantistici.\nIl corso ",(0,a.jsx)(e.em,{children:"Basics of quantum information"})," su questa piattaforma copre questo materiale ed \xe8 consigliato come primo approccio per chi \xe8 alle prime armi con il quantum computing."]}),"\n",(0,a.jsx)(e.h2,{id:"the-story-of-computation",children:"La storia della computazione"}),"\n",(0,a.jsxs)(e.p,{children:["Il quantum computing \xe8 una nuova e stimolante tecnologia in una fase iniziale di sviluppo \u2014 ma \xe8 solo un capitolo di una storia che risale a migliaia di anni fa.\n\xc8 la storia della ",(0,a.jsx)(e.em,{children:"computazione"})," e dei suoi molteplici legami con il ",(0,a.jsx)(e.em,{children:"mondo fisico"}),"."]}),"\n",(0,a.jsx)(e.h3,{id:"computing-devices-since-ancient-times",children:"Dispositivi di calcolo dall'antichit\xe0"}),"\n",(0,a.jsxs)(e.p,{children:["Sin dall'antichit\xe0, gli esseri umani hanno avuto la necessit\xe0 di eseguire ",(0,a.jsx)(e.em,{children:"calcoli"})," \u2014 ossia di elaborare informazioni secondo determinate regole e vincoli \u2014 per abilitare la comunicazione, la costruzione, il commercio, la scienza e altri aspetti della vita.\nCi siamo rivolti al mondo fisico per trovare supporto, e attraverso scoperte ingegnose abbiamo costruito dispositivi che ci aiutassero a calcolare."]}),"\n",(0,a.jsxs)(e.p,{children:["In tempi remoti, oggetti in legno, osso e corde annodate conservavano informazioni e facilitavano i calcoli.\nDispositivi meccanici costruiti con leve, ingranaggi e altri meccanismi si sono evoluti dai primi orologi astronomici a calcolatrici, fino a sofisticati dispositivi di calcolo come gli analizzatori differenziali, che risolvevano equazioni tramite ruote e dischi rotanti.\nAnche la tecnologia della scrittura ha svolto un ruolo importante in questa storia, consentendo alle ",(0,a.jsx)(e.em,{children:"persone"})," di eseguire calcoli che altrimenti non sarebbero riuscite a fare."]}),"\n",(0,a.jsx)(e.p,{children:"Quando pensiamo ai computer oggi, tendiamo a pensare ai computer digitali elettronici.\nMa questa \xe8 in realt\xe0 una tecnologia abbastanza recente: i computer digitali elettronici furono costruiti per la prima volta negli anni '40.\n(Al confronto, si ritiene che l'abaco sumero sia stato inventato tra il 2700 e il 2300 a.C.)\nLa tecnologia ha fatto passi da gigante da allora e i computer sono ormai onnipresenti.\nLi troviamo nelle case, nei luoghi di lavoro e nei veicoli che ci trasportano tra di essi, e molti di noi li portano con s\xe9 ovunque vadano."}),"\n",(0,a.jsxs)(e.p,{children:["Abbiamo anche i ",(0,a.jsx)(e.em,{children:"supercomputer"}),", che sono grandi insiemi di potenti processori classici collegati in parallelo.\nSono tra i migliori strumenti mai costruiti dall'uomo per risolvere problemi difficili, e la loro potenza e affidabilit\xe0 continuano ad avanzare.\nEppure ci sono importanti problemi computazionali che nemmeno questi giganti saranno mai in grado di risolvere, a causa della difficolt\xe0 computazionale intrinseca di tali problemi."]}),"\n",(0,a.jsx)(e.h3,{id:"connections-to-the-physical-world",children:"Connessioni con il mondo fisico"}),"\n",(0,a.jsxs)(e.p,{children:["I computer hanno molti usi.\nUn uso importante dei computer \xe8 quello di ",(0,a.jsx)(e.em,{children:"conoscere"})," il mondo fisico e comprenderne meglio i modelli.\nGli usi storici in questa categoria hanno incluso la previsione di eclissi e maree, la comprensione del movimento dei corpi astronomici e (in tempi relativamente pi\xf9 recenti) la modellazione delle esplosioni.\nOggi non c'\xe8 quasi un laboratorio di fisica al mondo senza un computer."]}),"\n",(0,a.jsxs)(e.p,{children:["Pi\xf9 in generale, fisica e computazione sono sempre state intrecciate.\nLa computazione non pu\xf2 esistere nel vuoto: l'informazione richiede un mezzo, e per calcolare dobbiamo sfruttare il mondo fisico in qualche misura.\nRolf Landauer, informatico (e dipendente IBM), riconobbe decenni fa che l'informazione \xe8 fisica, esistente solo attraverso una rappresentazione fisica.\nIl ",(0,a.jsx)(e.em,{children:"principio di Landauer"})," stabilisce una connessione tra l'informazione e le leggi della termodinamica, ma in realt\xe0 le connessioni sono molte."]}),"\n",(0,a.jsx)(e.p,{children:"Comprendere il mondo fisico \xe8 l'obiettivo della fisica come disciplina, ma in realt\xe0 si tratta di una strada a doppio senso.\nAttraverso la nostra comprensione del mondo fisico siamo in grado di sfruttare nuove tecnologie per aiutarci a calcolare, e attraverso di esse continuiamo a imparare sul mondo fisico \u2014 tirando in sostanza su fisica e tecnologia computazionale per i propri capelli."}),"\n",(0,a.jsx)(e.h3,{id:"moores-law",children:"La legge di Moore"}),"\n",(0,a.jsx)(e.p,{children:"La legge di Moore \xe8 un'osservazione secondo cui il numero massimo di transistor in un circuito integrato raddoppia circa ogni 2 anni.\nNel corso degli ultimi 5 decenni circa, non solo abbiamo osservato questa tendenza, ma ne abbiamo anche raccolto i frutti.\nCon pi\xf9 transistor su un chip possiamo eseguire calcoli pi\xf9 complessi e farlo pi\xf9 velocemente.\nEcco perch\xe9 i computer sono diventati sempre pi\xf9 potenti nel tempo."}),"\n",(0,a.jsx)(e.p,{children:'Tuttavia, la "legge" di Moore sta per necessit\xe0 giungendo al termine.\nGli esperti non concordano su quando ci\xf2 accadr\xe0, e alcuni sostengono che sia gi\xe0 accaduto.\nMa sappiamo con certezza che deve inevitabilmente finire perch\xe9 c\'\xe8 un limite teorico alla miniaturizzazione dei componenti di calcolo.\nNon possiamo rendere un transistor pi\xf9 piccolo di un atomo!\nPer quanto possa sembrare esagerato, \xe8 il muro verso cui ci stiamo avvicinando.'}),"\n",(0,a.jsx)(e.p,{children:'La soluzione non \xe8 arrendersi e dire: "Beh, \xe8 il massimo che possiamo ottenere."\nQuesto va contro la natura umana.\nDobbiamo invece rivolgerci al mondo fisico per trovare nuovi strumenti computazionali, ed \xe8 qui che entra in gioco il quantum computing.'}),"\n",(0,a.jsx)(e.h2,{id:"quantum-computing",children:"Quantum computing"}),"\n",(0,a.jsx)(e.h3,{id:"quantum-mechanics-and-computation",children:"La meccanica quantistica e la computazione"}),"\n",(0,a.jsx)(e.p,{children:"La meccanica quantistica fu scoperta all'inizio del XX secolo e ha gi\xe0 svolto un ruolo importante nella computazione.\nIn effetti, la nostra comprensione della meccanica quantistica ha, in parte, reso possibili i computer moderni.\nSenza la meccanica quantistica, per esempio, \xe8 difficile immaginare che l'hard disk allo stato solido sarebbe stato inventato."}),"\n",(0,a.jsx)(e.h3,{id:"quantum-computing-in-theory",children:"Il quantum computing in teoria"}),"\n",(0,a.jsx)(e.p,{children:"Quando Richard Feynman propose per la prima volta l'idea di un computer quantistico nel 1982, il suo obiettivo era simulare sistemi quantomeccanici.\nI calcoli necessari per farlo sembravano troppo difficili per i computer ordinari \u2014 ma forse, con un computer che opera secondo una descrizione quantomeccanica del mondo, i sistemi avrebbero potuto essere emulati direttamente."}),"\n",(0,a.jsx)(e.p,{children:"Oggi questa \xe8 una delle strade pi\xf9 promettenti per il quantum computing.\nPer quanto ne sappiamo, la Natura non \xe8 classica \u2014 \xe8 quantistica.\nE quindi i computer quantistici potrebbero essere strumenti preziosi per comprenderla.\nI computer classici, d'altra parte, possono solo approssimare ci\xf2 che accade realmente in Natura, e in alcuni casi tali\napprossimazioni sono molto limitate."}),"\n",(0,a.jsx)(e.p,{children:"Un modo per pensarci \xe8 attraverso un'analogia con le gallerie del vento.\nLa fluidodinamica \xe8 notoriamente difficile da simulare e prevedere matematicamente.\nAd esempio, \xe8 troppo costoso e impraticabile simulare un'auto che viaggia nel vento, cos\xec i produttori di automobili costruiscono effettivamente gallerie con vento soffiante e ci guidano le auto per testarne le prestazioni.\nCio\xe8, creano il vento invece di simularlo.\nCostruire un computer quantistico per studiare il mondo fisico \xe8 un po' come costruire una galleria del vento per studiare come il vento influenza le auto.\nI computer quantistici possono emulare direttamente le leggi della Natura a livello molecolare perch\xe9 agiscono in conformit\xe0 con quelle leggi,\nil che significa che emulano la Natura invece di simularla tramite formule e calcoli."}),"\n",(0,a.jsxs)(e.p,{children:["Altri seguirono le idee di Feynman \u2014 e le collegarono a una teoria dell'",(0,a.jsx)(e.em,{children:"informazione quantistica"})," che\nera gi\xe0 in fase di sviluppo.\nNacque il campo dell'",(0,a.jsx)(e.em,{children:"informazione e computazione quantistica"}),".\nDa allora si \xe8 sviluppato in un ricco campo di studio multidisciplinare, e numerosi vantaggi dell'informazione e della computazione quantistica rispetto a quella classica sono stati identificati in un'ampia variet\xe0 di contesti ",(0,a.jsx)(e.em,{children:"teorici"})," riguardanti comunicazione, computazione e crittografia."]}),"\n",(0,a.jsx)(e.h3,{id:"quantum-computing-in-practice",children:"Il quantum computing in pratica"}),"\n",(0,a.jsx)(e.p,{children:"In termini pratici, due cose sono necessarie per trasferire questi tipi di vantaggi teorici in vantaggi nel mondo reale: i dispositivi stessi e le metodologie per sbloccare il loro potenziale."}),"\n",(0,a.jsx)(e.p,{children:"A differenza dei computer classici, nessuno ha un computer quantistico in tasca.\nFino a poco tempo fa, se volevi sperimentare con un computer quantistico, dovevi costruirlo e mantenerlo tu stesso\n(di solito in un triste laboratorio in un seminterrato di un'universit\xe0 o di un centro di ricerca), e avresti avuto al massimo pochi qubit, molto rumorosi.\nQuesto non \xe8 pi\xf9 il caso.\nNel 2016, IBM Quantum\xae ha messo il primo processore quantistico nel cloud.\nAveva solo 5 qubit e tassi di errore abbastanza elevati, ma da allora abbiamo fatto molta strada.\nRiassumeremo lo stato attuale della tecnologia in una sezione qui sotto."}),"\n",(0,a.jsx)(e.p,{children:"Oltre a costruire computer quantistici, dobbiamo anche sviluppare metodologie per usarli efficacemente.\nMentre i progressi teorici negli algoritmi e nei protocolli quantistici suggeriscono un forte potenziale, la sfida di trovare usi pratici per il quantum computing \xe8 ancora davanti a noi.\nI computer quantistici di oggi non possono ancora eseguire i calcoli fault-tolerant necessari per trasferire i vantaggi teorici noti in vantaggi pratici.\nMa sono al di l\xe0 della portata delle simulazioni su computer classici, e possiamo puntare a sfruttare questo fatto per ottenere potenza di calcolo."}),"\n",(0,a.jsx)(e.p,{children:"Con questi progressi ci troviamo con un nuovo strumento di calcolo, e sta a noi capire cosa possiamo farne."}),"\n",(0,a.jsx)(e.h3,{id:"potential-applications",children:"Potenziali applicazioni"}),"\n",(0,a.jsx)(e.p,{children:"Non ci si aspetta che il quantum computing sia utile per studiare come si comportano le auto nel vento.\nMa esistono altri processi fisici \u2014 come quelli coinvolti nella progettazione di batterie o in determinate reazioni chimiche \u2014 in cui la capacit\xe0 di un computer quantistico di emulare la Natura potrebbe portare a un quantum advantage.\nPi\xf9 in generale, ci sono molti problemi troppo difficili o costosi anche per i supercomputer pi\xf9 avanzati, inclusi problemi altamente rilevanti per la nostra societ\xe0.\nIl quantum computing potrebbe non offrire soluzioni a tutti, ma potrebbe offrire soluzioni ad alcuni."}),"\n",(0,a.jsx)(e.p,{children:"Le seguenti tre aree applicative rappresentano obiettivi nel campo del quantum computing rumoroso, prima dell'implementazione della correzione degli errori quantistici e della fault-tolerance."}),"\n",(0,a.jsxs)(e.ul,{children:["\n",(0,a.jsx)(e.li,{children:"Ottimizzazione"}),"\n",(0,a.jsx)(e.li,{children:"Simulare la Natura"}),"\n",(0,a.jsx)(e.li,{children:"Trovare struttura nei dati (incluso il machine learning)"}),"\n"]}),"\n",(0,a.jsx)(e.p,{children:"Discuteremo questi argomenti in modo pi\xf9 dettagliato pi\xf9 avanti nel corso."}),"\n",(0,a.jsx)(e.h3,{id:"state-of-the-technology",children:"Stato della tecnologia"}),"\n",(0,a.jsx)(e.p,{children:"Costruire computer quantistici \xe8 una sfida tecnologica difficile, e sono solo 8 anni che piccoli computer quantistici sono disponibili al pubblico.\nIn questi 8 anni abbiamo fatto progressi su molti fronti."}),"\n",(0,a.jsxs)(e.p,{children:["Numerosi processori quantistici IBM sono ora accessibili tramite cloud, tutti con oltre 100 qubit.\nMa non \xe8 solo la dimensione dei processori a essere importante \u2014 \xe8 solo una delle metriche che ci interessano.\nAnche la qualit\xe0 dei gate \xe8 migliorata drasticamente, e abbiamo anche introdotto metodi per ridurre e mitigare gli errori intrinseci ai sistemi quantistici, anche mentre spingiamo avanti verso la creazione di sistemi fault-tolerant.\nTre metriche fondamentali \u2014 ",(0,a.jsx)(e.em,{children:"scala"}),", ",(0,a.jsx)(e.em,{children:"qualit\xe0"})," e ",(0,a.jsx)(e.em,{children:"velocit\xe0"})," \u2014 sono essenziali per monitorare i miglioramenti delle prestazioni."]}),"\n",(0,a.jsxs)(e.ul,{children:["\n",(0,a.jsxs)(e.li,{children:["\n",(0,a.jsxs)(e.p,{children:[(0,a.jsx)(e.strong,{children:"Dimensione."})," Pi\xf9 qubit sono ovviamente meglio, ma solo se aumentarne il numero non degrada le prestazioni\n(cosa che pu\xf2 accadere). In realt\xe0, vogliamo pi\xf9 qubit di buona qualit\xe0 che non interferiscano tra loro\nattraverso il crosstalk quando non lo vogliamo. Anche il modo in cui i qubit sono collegati tra loro \xe8 importante, e\ncapire come farlo al meglio rappresenta una sfida per i circuiti con qubit superconduttori."]}),"\n"]}),"\n",(0,a.jsxs)(e.li,{children:["\n",(0,a.jsxs)(e.p,{children:[(0,a.jsx)(e.strong,{children:"Qualit\xe0."})," Un'altra metrica importante che osserviamo, per monitorare il miglioramento delle prestazioni nel tempo, \xe8 la fedelt\xe0 dei gate a 2 qubit.\nI gate che operano su singoli qubit non sono soggetti a errori quanto i gate a 2 qubit, che sono quindi la preoccupazione maggiore.\n(I gate a 2 qubit sono anche cruciali perch\xe9 sono responsabili della creazione dell'entanglement tra i qubit, che \xe8\nipotizzato essere uno dei fenomeni fisici che conferisce al quantum computing la sua potenza.)"]}),"\n"]}),"\n",(0,a.jsxs)(e.li,{children:["\n",(0,a.jsxs)(e.p,{children:[(0,a.jsx)(e.strong,{children:"Velocit\xe0."})," Infine c'\xe8 la velocit\xe0 e l'efficienza. In breve, il tempo trascorso nell'esecuzione di un programma (incluse sia le parti quantistiche che\nquelle classiche) dovrebbe essere il pi\xf9 breve possibile."]}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(e.h2,{id:"conclusion",children:"Conclusione"}),"\n",(0,a.jsx)(e.p,{children:"\xc8 davvero un momento entusiasmante per lavorare nel campo del quantum computing: per la prima volta nella storia possiamo iniziare a esplorare una regione del calcolo che va oltre la computazione classica."}),"\n",(0,a.jsx)(e.p,{children:"T.J. Watson una volta predisse famosamente un mercato mondiale per pochi computer.\nPotremmo ridere ora di quanto si fosse sbagliato \u2014 ma nel farlo dobbiamo riconoscere che abbiamo il vantaggio del senno di poi.\nE dovremmo anche riconoscere che, come esseri umani, abbiamo una tendenza generale a sottostimare enormemente il potenziale delle tecnologie future.\nOra che \xe8 il nostro turno e assumiamo il ruolo di pionieri del quantum computing, dovremmo tenerlo a mente."}),"\n",(0,a.jsx)(e.p,{children:"Il quantum computing \xe8 spesso contrapposto al calcolo classico, come qualcosa di nettamente diverso da esso e in competizione con esso.\nMa da una prospettiva pi\xf9 ampia possiamo vedere il quantum computing semplicemente come un altro capitolo di una lunga storia.\n\xc8 nella nostra natura come esseri umani cercare nuovi modi di calcolare e sfruttare la potenza che il mondo naturale ci offre per farlo.\nLo facciamo da secoli.\nIl quantum computing ci offre un nuovo strumento in questa impresa e sta a noi scoprire come possiamo sfruttare la potenza che ci mette a disposizione."})]})}function m(i={}){const{wrapper:e}={...(0,t.R)(),...i.components};return e?(0,a.jsx)(e,{...i,children:(0,a.jsx)(u,{...i})}):u(i)}},28453(i,e,o){o.d(e,{R:()=>r,x:()=>s});var n=o(96540);const a={},t=n.createContext(a);function r(i){const e=n.useContext(t);return n.useMemo(function(){return"function"==typeof i?i(e):{...e,...i}},[e,i])}function s(i){let e;return e=i.disableParentContext?"function"==typeof i.components?i.components(a):i.components||a:r(i.components),n.createElement(t.Provider,{value:e},i.children)}}}]);